import { useState } from 'react';
import { Search, Filter, ChevronDown, RefreshCw, Layers, Binary, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { clsx } from 'clsx';

interface GroupSearchFilterProps {
  initialSearch: string;
  initialPeriodId: string;
  initialStatus: string;
  periods: Array<{ id: number; name: string }>;
  onApplyFilters: (filters: { search: string; periodId: string; status: string }) => void;
}

export const GroupSearchFilter = ({
  initialSearch,
  initialPeriodId,
  initialStatus,
  periods,
  onApplyFilters,
}: GroupSearchFilterProps) => {
  const [search, setSearch] = useState(initialSearch);
  const [periodId, setPeriodId] = useState(initialPeriodId);
  const [status, setStatus] = useState(initialStatus);
  const [showFilters, setShowFilters] = useState(false);

  const handleApply = () => {
    onApplyFilters({ search, periodId, status });
  };

  const handleReset = () => {
    setSearch('');
    setPeriodId('');
    setStatus('');
    onApplyFilters({ search: '', periodId: '', status: '' });
  };

  const activeFilterCount = (search ? 1 : 0) + (periodId ? 1 : 0) + (status ? 1 : 0);

  return (
    <div className="bg-white border border-emerald-50/50 rounded-xl overflow-hidden shadow-sm">
      <div className="p-4 flex flex-col lg:flex-row items-center gap-4">
        <div className="flex-1 w-full relative">
          <Search
            size={20}
            className="absolute left-6 top-1/2 -translate-y-1/2 text-emerald-800"
          />
          <input
            type="text"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleApply()}
            className="w-full h-12 pl-16 pr-6 bg-emerald-50/10 border border-emerald-50/30 rounded-xl text-sm font-bold text-emerald-950 focus:bg-white focus:border-[#f3f4f6]0 transition-all outline-none placeholder:text-black/20"
            placeholder="Cari Kelompok, Lokasi, atau Pembimbing..."
          />
        </div>
        <div className="flex items-center gap-2 w-full lg:w-auto">
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={clsx(
              'h-12 px-6 rounded-xl text-xs font-bold uppercase tracking-widest flex items-center gap-2 transition-all border',
              showFilters
                ? 'bg-[#16a34a] text-white border-emerald-600'
                : 'bg-white text-emerald-800 hover:text-emerald-600 hover:border-emerald-200'
            )}
          >
            <Filter size={18} /> 
            {activeFilterCount > 0 ? `Katalog (${activeFilterCount})` : 'Katalog'}
          </button>
          <button
            onClick={handleApply}
            className="h-12 px-8 bg-emerald-950 text-white rounded-xl text-xs font-bold uppercase tracking-widest active:scale-95 transition-all border border-emerald-900 shadow-lg shadow-emerald-900/20"
          >
            Terapkan
          </button>
        </div>
      </div>

      <AnimatePresence>
        {showFilters && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="bg-gray-50 border-t border-emerald-50/50 overflow-hidden"
          >
            <div className="p-8 space-y-8">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-emerald-950 uppercase tracking-widest ml-1 flex items-center gap-2">
                       <Layers size={14} className="text-[#1a7a4a]" /> Sesi Akademik
                    </label>
                    <div className="relative group/select">
                      <select
                        value={periodId}
                        onChange={(e) => setPeriodId(e.target.value)}
                        className="w-full h-11 px-4 rounded-xl border border-emerald-50 bg-white text-xs font-bold text-emerald-950 outline-none transition-all focus:border-[#f3f4f6]0 appearance-none pr-10 cursor-pointer uppercase tracking-tight"
                      >
                        <option value="">Semua Periode</option>
                        {(periods || []).map((p) => (
                          <option key={p.id} value={p.id}>
                            {p.name?.toUpperCase()}
                          </option>
                        ))}
                      </select>
                      <ChevronDown
                        size={14}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-emerald-800 pointer-events-none"
                      />
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-emerald-950 uppercase tracking-widest ml-1 flex items-center gap-2">
                       <RefreshCw size={14} className="text-[#1a7a4a]" /> Status Operasional
                    </label>
                    <div className="relative group/select">
                      <select
                        value={status}
                        onChange={(e) => setStatus(e.target.value)}
                        className="w-full h-11 px-4 rounded-xl border border-emerald-50 bg-white text-xs font-bold text-emerald-950 outline-none transition-all focus:border-[#f3f4f6]0 appearance-none pr-10 cursor-pointer uppercase tracking-tight"
                      >
                        <option value="">Semua Status</option>
                        <option value="draft">Draft / Persiapan</option>
                        <option value="active">Aktif / Lapangan</option>
                        <option value="closed">Ditutup / Arsip</option>
                      </select>
                      <ChevronDown
                        size={14}
                        className="absolute right-4 top-1/2 -translate-y-1/2 text-emerald-800 pointer-events-none"
                      />
                    </div>
                  </div>
                </div>
                <div className="flex justify-end gap-6 pt-6 border-t border-emerald-50/50">
                  <button
                    onClick={handleReset}
                    className="text-xs font-bold text-emerald-950 hover:text-rose-600 transition-colors uppercase tracking-widest flex items-center gap-2"
                  >
                    Atur Ulang
                  </button>
                </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

import { Link } from '@inertiajs/react';
import { MapPin, UserCheck, Pencil, Trash2, Info, ChevronRight, CheckCircle2, History, SearchX, ArrowUpRight } from 'lucide-react';
import { clsx } from 'clsx';
import { Pagination } from '@/Components/ui';
import type { PaginationMeta } from '@/Components/ui/Pagination';

interface Group {
  id: number;
  code: string;
  name: string;
  capacity: number;
  status: string;
  registrations_count: number;
  approved_participants_count: number;
  pending_participants_count: number;
  available_slots: number;
  ready_for_placement: boolean;
  placement_note: string;
  period?: { id: number; name: string } | null;
  location?: {
    id: number;
    village_name: string;
    district_name?: string | null;
    regency_name?: string | null;
    full_name: string;
  } | null;
  main_lecturer?: { id: number; name: string } | null;
}

interface GroupTableListProps {
  groups: {
    data: Group[];
    meta: PaginationMeta;
  };
  canManage: boolean;
  onEdit: (group: Group) => void;
  onDelete: (id: number) => void;
}

export const GroupTableList = ({
  groups = { data: [], meta: { total: 0, current_page: 1, last_page: 1, per_page: 15 } },
  canManage,
  onEdit,
  onDelete,
}: GroupTableListProps) => {
  return (
    <div className="bg-white border border-emerald-50/50 rounded-xl overflow-hidden shadow-sm">
      <div className="overflow-x-auto">
        <table className="w-full text-left font-sans">
          <thead className="bg-gray-50">
            <tr className="text-xs font-bold uppercase tracking-widest text-emerald-950">
              <th className="px-8 py-4 w-16 text-center">No</th>
              <th className="px-8 py-4">Identitas Unit</th>
              <th className="px-8 py-4">Wilayah & Sesi</th>
              <th className="px-8 py-4">Status & Mentor</th>
              <th className="px-8 py-4 text-center">Kapasitas</th>
              <th className="px-8 py-4 text-right">Detail</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-[#f3f4f6]">
            {groups.data.length === 0 ? (
              <tr>
                <td colSpan={6} className="py-32 text-center text-emerald-950/10">
                    <div className="flex flex-col items-center gap-4">
                        <SearchX size={64} strokeWidth={1} />
                        <p className="text-xs font-bold uppercase tracking-widest">Unit belum terarsip</p>
                    </div>
                </td>
              </tr>
            ) : (
              groups.data.map((group, idx) => (
                <tr key={group.id} className="group hover:bg-gray-50/10 transition-colors">
                  <td className="px-8 py-6 text-xs font-bold text-emerald-950/20 tabular-nums text-center uppercase">
                    {idx + 1 + (groups.meta.current_page - 1) * (groups.meta.per_page ?? 15)}
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex flex-col gap-1.5">
                      <span className="text-sm font-bold text-emerald-950 group-hover:text-emerald-600 transition-colors uppercase tracking-tight leading-none">
                        {group.name}
                      </span>
                      <span className="text-xs font-bold text-emerald-950 uppercase tracking-widest tabular-nums">
                         CODE_ID: {group.code}
                      </span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex flex-col gap-2">
                      <div className="flex items-center gap-2">
                        <MapPin size={14} className="text-emerald-600" />
                        <span className="text-xs font-bold text-emerald-950 uppercase leading-none tracking-tight">
                          {group.location?.village_name || 'BELUM DIALOKASI'}
                        </span>
                      </div>
                      <span className="text-xs font-bold text-emerald-950 uppercase tracking-widest ml-5">
                        SESI: {group.period?.name || '—'}
                      </span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="flex flex-col gap-2.5">
                      <div className="flex items-center gap-2">
                        <span
                          className={clsx(
                            'px-3 py-1.5 rounded-xl text-xs font-bold uppercase tracking-widest border shadow-sm',
                            group.status === 'active'
                              ? 'bg-[#e8f5ee] text-emerald-800 border-emerald-50'
                              : group.status === 'closed'
                              ? 'bg-rose-50 text-rose-600 border-rose-100'
                              : 'bg-amber-50 text-amber-700 border-amber-100',
                          )}
                        >
                          {group.status === 'draft'
                            ? 'PERSIAPAN'
                            : group.status === 'active'
                            ? 'LAPANGAN'
                            : 'ARSIP'}
                        </span>
                        {group.ready_for_placement && (
                           <div className="h-2 w-2 rounded-full bg-emerald-500 animate-pulse" title="SIAP PENEMPATAN" />
                        )}
                      </div>
                      <div className="flex items-center gap-2">
                        <UserCheck size={12} className="text-emerald-400" />
                        <span className="text-xs font-bold text-emerald-950 uppercase tracking-tight truncate max-w-[120px]">
                          {group.main_lecturer?.name || 'TANPA MENTOR'}
                        </span>
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <div className="space-y-2.5 w-32 mx-auto">
                      <div className="flex justify-between items-end">
                        <span className="text-sm font-bold text-emerald-950 tabular-nums">{group.approved_participants_count}</span>
                        <span className="text-xs font-bold text-emerald-950 uppercase tracking-widest">{group.capacity} PK</span>
                      </div>
                      <div className="h-1.5 bg-[#e8f5ee] rounded-full overflow-hidden border border-emerald-50/50">
                        <div
                          className={clsx(
                            'h-full rounded-full transition-all duration-1000',
                            group.approved_participants_count / group.capacity >= 1
                              ? 'bg-emerald-400'
                              : 'bg-emerald-600',
                          )}
                          style={{
                            width: `${Math.min(
                              100,
                              (group.approved_participants_count / group.capacity) * 100,
                            )}%`,
                          }}
                        />
                      </div>
                    </div>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                      <Link
                        href={`/admin/kelompok/${group.id}`}
                        className="h-10 px-6 bg-white border border-emerald-50 text-emerald-800 hover:text-emerald-800 hover:border-emerald-200 rounded-xl text-xs font-bold uppercase tracking-widest transition-all flex items-center justify-center shadow-sm active:scale-95 group/btn"
                      >
                        Pemeriksaan
                        <ArrowUpRight
                          size={14}
                          className="ml-2 group-hover/btn:translate-x-0.5 group-hover/btn:-translate-y-0.5 transition-transform"
                        />
                      </Link>
                      {canManage && (
                        <>
                          <button
                            onClick={() => onEdit(group)}
                            className="h-10 w-10 bg-white border border-emerald-50 text-emerald-800 hover:text-emerald-800 hover:border-emerald-200 rounded-xl flex items-center justify-center transition-all shadow-sm active:scale-95"
                          >
                            <Pencil size={14} />
                          </button>
                          <button
                            onClick={() => onDelete(group.id)}
                            className="h-10 w-10 bg-white border border-emerald-50 text-emerald-800 hover:text-rose-600 hover:border-rose-100 hover:bg-rose-50 rounded-xl flex items-center justify-center transition-all shadow-sm active:scale-95"
                          >
                            <Trash2 size={14} />
                          </button>
                        </>
                      )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      <div className="px-8 py-6 border-t border-[#f3f4f6] bg-emerald-50/10 flex flex-col lg:flex-row items-center justify-between gap-6">
        <span className="text-xs font-bold text-emerald-950 uppercase tracking-widest">
          HLMN {groups.meta.current_page} &middot; TOTAL {groups.meta.total} UNIT
        </span>
        <Pagination meta={groups.meta} />
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageSquare, X, Send, Loader2 } from 'lucide-react';
import axios from 'axios';

export default function AiAssistant() {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([{ role: 'assistant', text: 'Ada yang bisa saya bantu?' }]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);

  const send = async () => {
    if (!input.trim() || loading) return;
    const userMsg = { role: 'user', text: input };
    setMessages([...messages, userMsg]);
    setInput('');
    setLoading(true);
    try {
      const res = await axios.post('/ai/assistant', { message: input });
      setMessages(prev => [...prev, { role: 'assistant', text: res.data.answer }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'assistant', text: 'Gagal koneksi AI.' }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] flex flex-col items-end">
      <AnimatePresence>
        {isOpen && (
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: 20 }}
            className="mb-4 w-80 h-[400px] bg-white rounded-xl border border-emerald-50 flex flex-col overflow-hidden"
            style={{ boxShadow: '0 4px 12px rgba(0,0,0,0.15)' }}>
            <div className="p-4 bg-[#16a34a] text-white flex justify-between items-center">
              <span className="text-sm font-bold">Saizu AI</span>
              <X className="cursor-pointer h-5 w-5" onClick={() => setIsOpen(false)} />
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-[#fafafa]">
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`p-2.5 rounded-lg text-xs max-w-[80%] ${m.role === 'user' ? 'bg-[#16a34a] text-white' : 'bg-white border border-emerald-50 text-emerald-950'}`}>
                    {m.text}
                  </div>
                </div>
              ))}
              {loading && <Loader2 size={16} className="animate-spin text-[#16a34a]" />}
            </div>
            <div className="p-3 border-t border-emerald-50 flex gap-2 bg-white">
              <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && send()}
                className="flex-1 text-sm border border-gray-300 rounded-lg px-3 py-2 focus:border-[#16a34a] focus:ring-1 focus:ring-[#16a34a] outline-none text-emerald-950 placeholder:text-black" placeholder="Tanya sesuatu..." />
              <button onClick={send} className="p-2.5 bg-[#16a34a] text-white rounded-lg hover:bg-[#15803d] transition-colors">
                <Send size={14} />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="h-12 w-12 rounded-full bg-[#16a34a] text-white flex items-center justify-center hover:bg-[#15803d] transition-colors"
        style={{ boxShadow: '0 4px 12px rgba(0,0,0,0.15)' }}
      >
        {isOpen ? <X size={20} /> : <MessageSquare size={20} />}
      </button>
    </div>
  );
}

