      { label: 'Pengaturan Sertifikat', href: safeRoute('admin.pengaturan.sertifikat.index'), icon: Award },
      { label: 'Pengaturan Global', href: safeRoute('admin.pengaturan.sistem'), icon: Cpu },
    ],
  },
];

function getDosenNav(hasDplRole: boolean): NavGroup[] {
  const base: NavGroup = {
    title: 'PORTAL DOSEN',
    items: [
      { label: 'Beranda Dosen', href: safeRoute('dosen.dashboard'), icon: LayoutDashboard },
      { label: 'Workshop & Pembekalan', href: safeRoute('dosen.workshops.index'), icon: GraduationCap },
      { label: 'Sertifikat Workshop', href: safeRoute('dosen.workshops.my-certificates'), icon: Award },
    ],
  };

  if (!hasDplRole) return [base];

  return [
    base,
    {
      title: 'BIMBINGAN DPL',
      items: [
        { label: 'Data Kelompok', href: safeRoute('dosen.kelompok.index'), icon: Users },
        { label: 'Monitoring Mahasiswa', href: safeRoute('dosen.monitoring.index'), icon: Activity },
        { label: 'Penilaian Akhir', href: safeRoute('dosen.evaluations.index'), icon: Star },
        { label: 'Umpan Balik Peserta', href: safeRoute('dosen.feedback-dpl.index'), icon: MessageSquareQuote },
      ],
    },
  ];
}

function buildStudentNav(currentPhase: string, registrationStatus: string = 'none'): NavGroup[] {
  const isExecutionOrLater = ['execution', 'grading', 'finished'].includes(currentPhase);
  const isGradingOrLater = ['grading', 'finished'].includes(currentPhase);

  const isApproved = registrationStatus === 'approved';

  return [
    {
      title: 'SENTRAL MAHASISWA',
      items: [
        { label: 'Beranda Mahasiswa', href: safeRoute('student.dashboard'), icon: LayoutDashboard },
        ...(!isApproved
          ? [
            { label: 'Daftar KKN', href: '/mahasiswa/daftar', icon: ClipboardList },
          ]
          : []),
        ...(isApproved || isExecutionOrLater
          ? [
            {
              label: 'Logbook Masuk',
              href: safeRoute('student.laporan-harian.index'),
              icon: FileText,
            },
            {
              label: 'Target Proker',
              href: safeRoute('student.program-kerja.index'),
              icon: BookOpen,
            },
          ]
          : []),
        ...(isGradingOrLater
          ? [
            {
              label: 'Evaluasi DPL',
              href: safeRoute('student.evaluasi-dpl.index'),
              icon: MessageSquareQuote,
            },
            {
              label: 'Sertifikat KKN',
              href: safeRoute('student.certificate.index'),
              icon: Award,
            },
            {
              label: 'Sertifikat Workshop',
              href: safeRoute('student.workshops.my-certificates'),
              icon: GraduationCap,
            },
          ]
          : []),
      ],
    },
  ];
}

function getNavForRole(roles: string[], currentPhase: string, registrationStatus: string = 'none'): NavGroup[] {
  const norm = roles.map((r) => r.toLowerCase());
  if (norm.includes('admin') || norm.includes('superadmin')) return getAdminNav();
  if (norm.includes('dosen') || norm.includes('dpl')) return getDosenNav(norm.includes('dpl'));
  return buildStudentNav(currentPhase, registrationStatus);
}

interface SidebarProps {
  open: boolean;
  onClose: () => void;
}

export default function Sidebar({ open, onClose }: SidebarProps) {
  const { props, url } = usePage<PageProps & { url: string }>();
  const { auth } = props;

  const roles =
    (auth.user?.roles as any[])?.map((r) => (typeof r === 'string' ? r : (r as any).name)) || [];
  const currentPhase = (auth as any)?.active_phase ?? 'upcoming';
  const registrationStatus = (auth as any)?.user?.student_registration_status ?? 'none';
  const navGroups = getNavForRole(roles, currentPhase, registrationStatus);
  const currentPath = url;

  const navRef = useRef<HTMLDivElement>(null);
  const activeItemRef = useRef<HTMLAnchorElement>(null);

  // Restore scroll once on mount
  useEffect(() => {
    if (navRef.current) {
      const savedScroll = sessionStorage.getItem('sidebar-scroll');
      if (savedScroll) {
        navRef.current.scrollTop = parseInt(savedScroll, 10);
      }
    }
  }, []);

  const handleScroll = (e: React.UIEvent<HTMLDivElement>) => {
    sessionStorage.setItem('sidebar-scroll', e.currentTarget.scrollTop.toString());
  };

  return (
    <>
      {/* Mobile overlay */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-40 bg-black/20 backdrop-blur-sm lg:hidden"
            onClick={onClose}
          />
        )}
      </AnimatePresence>

      <aside
        className={clsx(
          'fixed inset-y-0 left-0 z-50 w-64 bg-[#F8FAF9] border-r border-emerald-100/50 shadow-sm flex flex-col transition-transform duration-300 lg:translate-x-0',
          open ? 'translate-x-0 shadow-xl' : '-translate-x-full',
        )}
      >
        {/* LOGO AREA - Brand Identity */}
        <div className="h-28 px-6 flex flex-col justify-center sticky top-0 z-10">
          <div className="flex items-center gap-3">
            <div className="h-12 w-12 flex items-center justify-center bg-white rounded-2xl border border-emerald-100 p-1.5 shadow-sm shrink-0">
              <img src="/images/logo_uinsaizu.png" alt="Logo UIN SAIZU" className="h-full w-full object-contain" />
            </div>
            <div className="h-12 w-12 flex items-center justify-center bg-white rounded-2xl border border-emerald-100 p-1 shadow-sm shrink-0">
              <img src="/images/logo_siberdaya.png" alt="Logo Siberdaya" className="h-full w-full object-contain" />
            </div>
          </div>
          <div className="mt-3">
            <h1 className="text-sm font-black text-emerald-950 leading-none tracking-tight flex items-center gap-1.5">
              SIBERDAYA <span className="h-1 w-1 rounded-full bg-emerald-500" />
            </h1>
            <p className="text-[9px] font-black text-emerald-600/60 mt-1 uppercase tracking-[0.15em] truncate">
               {roles.some(r => ['admin', 'superadmin'].includes(r))
                ? 'Sistem Manajemen KKN'
                : 'Portal Layanan KKN'}
            </p>
          </div>
        </div>

        {/* NAVIGATION AREA */}
        <nav
          ref={navRef}
          onScroll={handleScroll}
          className="flex-1 overflow-y-auto px-4 py-4 scrollbar-hide scroll-smooth space-y-8"
        >
          {navGroups.map((group, groupIdx) => (
            <div key={group.title} className="space-y-1.5">
              <h3 className="px-3 text-[10px] font-black text-emerald-900/40 uppercase tracking-widest">
                {group.title}
              </h3>

              <div className="space-y-1">
                {group.items.map((item) => {
                  const getPath = (href: string) => {
                    try {
                      return new URL(href, window.location.origin).pathname;
                    } catch (e) {
                      return href;
                    }
                  };

                  const itemPath = getPath(item.href);
                  const normalizedCurrentPath = currentPath.split('?')[0];

                  const isActive = normalizedCurrentPath === itemPath;

                  const isValidHref = item.href && item.href !== '#';
                  return (
                    <Link
                      key={item.href}
                      ref={isActive ? activeItemRef : null}
                      href={isValidHref ? item.href : '#'}
                      method={isValidHref ? 'get' : undefined}
                      preserveScroll
                      onClick={(e) => {
                        if (!isValidHref) {
                          e.preventDefault();
                        }
                        if (isValidHref && window.innerWidth < 1024) {
                          onClose();
                        }
                      }}
                      className={clsx(
                        'flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm transition-all duration-200 group relative',
                        isActive
                          ? 'bg-white text-emerald-700 font-bold shadow-sm border border-emerald-100'
                          : 'text-slate-500 hover:text-emerald-900',
                      )}
                    >
                      <item.icon
                        className={clsx(
                          'h-5 w-5 shrink-0 transition-colors',
                          isActive
                            ? 'text-emerald-600'
                            : 'text-slate-400 group-hover:text-emerald-500',
                        )}
                        strokeWidth={isActive ? 2.5 : 2}
                      />
                      <span className="truncate">
                        {item.label}
                      </span>
                    </Link>
                  );
                })}
              </div>
            </div>
          ))}
        </nav>

        {/* BOTTOM PROFILE - Premium Style */}
        <div className="p-4 mt-auto">
          <Link
            href={safeRoute('profile.show')}
            className="flex items-center gap-3 p-3 rounded-2xl bg-white border border-emerald-100 shadow-sm hover:shadow-md transition-all group"
          >
            <div className="h-10 w-10 rounded-xl bg-emerald-600 flex items-center justify-center text-white shrink-0 shadow-inner">
               <span className="text-xs font-black uppercase">{auth.user.name.substring(0, 2)}</span>
            </div>
            <div className="flex flex-col min-w-0">
              <span className="text-xs font-black text-emerald-950 truncate leading-none mb-1">
                {auth.user.name}
              </span>
              <span className="text-[9px] font-bold text-emerald-600 uppercase tracking-wider flex items-center gap-1">
                <div className="w-1 h-1 rounded-full bg-emerald-500 animate-pulse" />
                {roles[0] || 'User'}
              </span>
            </div>
          </Link>
        </div>
      </aside>
    </>
  );
}

import { type FormEvent, useEffect, useState } from 'react';
import { Head, router } from '@inertiajs/react';
import {
  Download,
  FileSpreadsheet,
  GraduationCap,
  Lock,
  Search,
  ShieldCheck,
  Users,
  Activity,
  RefreshCw,
  Filter,
  CheckCircle2,
  FileText
} from 'lucide-react';
import { clsx } from 'clsx';
import { route } from 'ziggy-js';
import { motion, AnimatePresence } from 'framer-motion';
import AppLayout from '@/Layouts/AppLayout';
import { Button } from '@/Components/ui';

interface StudentGrade {
  id: number;
  score_id: number | null;
  nim: string;
  name: string;
  group_name: string;
  kelompok_id: number;
  final_grade_letter: string | null;
  final_grade_value: number | string | null;
  is_locked: boolean;
  fakultas?: string | null;
  prodi?: string | null;
  can_finalize?: boolean;
}

interface Props {
  stats: { total_students: number; graded_count: number; locked_count: number; average_value: number; } | null;
  filters: { search?: string | null; period_id?: number | string | null; faculty_id?: number | string | null; kelompok_id?: number | string | null; huruf?: string | null; };
  periods: Array<{ id: number; name: string }>;
  faculties: Array<{ id: number; name: string }>;
  lockedFaculty?: { id: number; name: string } | null;
  canExport: boolean;
  canFinalizeMass: boolean;
  scores: StudentGrade[] | null;
}

export default function RekapNilaiIndex({
  scores, stats, filters, periods, faculties, lockedFaculty, canExport, canFinalizeMass,
}: Props) {
  const [search, setSearch] = useState(filters.search ? String(filters.search) : '');
  const [periodId, setPeriodId] = useState(filters.period_id ? String(filters.period_id) : '');
  const [facultyId, setFacultyId] = useState(filters.faculty_id ? String(filters.faculty_id) : '');
  const [huruf, setHuruf] = useState(filters.huruf ? String(filters.huruf) : '');
  const [certProgress, setCertProgress] = useState<{ status: 'idle' | 'processing' | 'completed' | 'failed'; progress: number; processed: number; total: number; download_url?: string; }>({ status: 'idle', progress: 0, processed: 0, total: 0 });

  useEffect(() => {
    let interval: ReturnType<typeof setInterval>;
    if (certProgress.status === 'processing') {
      interval = setInterval(() => {
        fetch(route('admin.grade-reports.progres-sertifikat', { period_id: periodId }))
          .then(res => res.json())
          .then(data => { if (data) setCertProgress(prev => ({ ...prev, status: data.status, progress: data.progress || 0, processed: data.processed || 0, total: data.total || 0, download_url: data.download_url })); });
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [certProgress.status, periodId]);

  const applyFilters = (event?: FormEvent) => {
    event?.preventDefault();
    router.get(route('admin.grade-reports.index'), {
      search: search || undefined,
      period_id: periodId || undefined,
      faculty_id: lockedFaculty ? lockedFaculty.id : facultyId || undefined,
      huruf: huruf || undefined
    }, { preserveState: true, preserveScroll: true, replace: true });
  };

  const handleFinalize = (scoreId: number) => {
    if (confirm('Lakukan kunci nilai pada mahasiswa ini? Data yang dikunci tidak dapat diubah kembali.')) {
      router.patch(route('admin.grade-reports.finalisasi', scoreId), {}, { preserveScroll: true });
    }
  };

  const handleBulkFinalize = () => {
    if (!periodId) return;
    if (confirm('Kunci seluruh nilai yang sudah lengkap secara massal?')) {
      router.post(route('admin.grade-reports.finalisasi-massal'), { period_id: periodId }, { preserveScroll: true });
    }
  };

  const exportWithPath = (path: 'ekspor' | 'ekspor-ledger') => {
    if (!periodId) return;
    const params = new URLSearchParams();
    params.set('period_id', periodId);
    if (lockedFaculty) params.set('faculty_id', String(lockedFaculty.id));
    else if (facultyId) params.set('faculty_id', facultyId);
    if (search) params.set('search', search);
    if (huruf) params.set('huruf', huruf);
    window.location.href = `${path === 'ekspor' ? route('admin.grade-reports.ekspor') : route('admin.grade-reports.ekspor-ledger')}?${params.toString()}`;
  };

  const [previewData, setPreviewData] = useState<{ open: boolean; loading: boolean; base64: string | null; filename: string | null }>({ open: false, loading: false, base64: null, filename: null });

  const handlePreview = async (scoreId: number) => {
    setPreviewData({ open: true, loading: true, base64: null, filename: null });
    try {
      const response = await fetch(route('admin.grade-reports.preview-sertifikat', scoreId));
      const data = await response.json();
      if (data.success) {
        setPreviewData({ open: true, loading: false, base64: data.preview, filename: data.filename });
      } else {
        alert('Gagal memuat pratinjau: ' + data.message);
        setPreviewData(prev => ({ ...prev, open: false, loading: false }));
      }
    } catch (e) {
      alert('Terjadi kesalahan saat memuat pratinjau.');
      setPreviewData(prev => ({ ...prev, open: false, loading: false }));
    }
  };

  const handleDownloadWord = (scoreId: number) => {
    window.location.href = route('admin.grade-reports.sertifikat-word', scoreId);
  };

  const handleBulkCertificates = () => {
    if (!periodId) return;
    if (confirm('Mulai proses pembuatan sertifikat massal?')) {
      setCertProgress({ status: 'processing', progress: 0, processed: 0, total: 0 });
      router.post(route('admin.grade-reports.sertifikat-massal'), { period_id: periodId, faculty_id: facultyId || undefined }, { preserveScroll: true });
    }
  };

  return (
    <AppLayout title="Rekap Nilai">

      <div className="py-8 font-sans transition-all">
        {/* Header Sederhana Sesuai Patokan Gold Standard */}
        <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-8 border-b border-emerald-50/50 pb-8">
          <div className="space-y-1">
            <h1 className="text-xl font-bold text-emerald-950">Rekapitulasi Nilai.</h1>
            <p className="text-xs text-emerald-950/40 font-black uppercase tracking-widest">Pusat pemeriksaan nilai akhir KKN mahasiswa</p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            {canExport && (
              <Button onClick={() => exportWithPath('ekspor')} variant="outline" className="h-9 border-emerald-50 text-emerald-950 hover:bg-gray-50 text-xs font-black uppercase tracking-widest px-4">
                <FileSpreadsheet size={16} className="mr-2 opacity-30" /> Ekspor Data
              </Button>
            )}
            {canFinalizeMass && (
              <Button onClick={handleBulkFinalize} className="h-9 bg-[#16a34a] hover:bg-[#15803d] text-white text-xs font-black uppercase tracking-widest px-4">
                <ShieldCheck size={16} className="mr-2" /> Kunci Massal
              </Button>
            )}
            <div className="relative">
              <Button onClick={handleBulkCertificates} disabled={certProgress.status === 'processing'} className="h-9 bg-emerald-950 hover:bg-black text-white text-xs font-black uppercase tracking-widest px-4">
                {certProgress.status === 'processing' ? <RefreshCw className="animate-spin mr-2" size={16} /> : <GraduationCap size={16} className="mr-2" />}
                Cetak Sertifikat
              </Button>
            </div>
          </div>
        </div>

        {/* Statistik Minimalis */}
        {stats && (
          <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
            <MiniStat icon={Users} label="Total Peserta" value={stats.total_students} />
            <MiniStat icon={Activity} label="Sudah Dinilai" value={stats.graded_count} />
            <MiniStat icon={Lock} label="Sudah Dikunci" value={stats.locked_count} />
            <MiniStat icon={CheckCircle2} label="Rerata Nilai" value={Number(stats.average_value || 0).toFixed(2)} />
          </div>
        )}

        {/* --- DATA TABLE CARD (Gold Standard) --- */}
        <div className="bg-white border border-emerald-50 rounded-xl shadow-sm overflow-hidden min-h-[500px]">
          {/* Toolbar Toolbar Sederhana Sesuai Patokan */}
          <div className="p-4 border-b border-[#f3f4f6]/50 bg-emerald-50/10 flex flex-col md:flex-row items-center justify-between gap-4">
            <div className="relative w-full md:w-80">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-emerald-950/20" />
              <input 
                type="text" 
                value={search} 
                onChange={(e) => setSearch(e.target.value)} 
                onKeyDown={(e) => e.key === 'Enter' && applyFilters()}
                placeholder="Cari NIM atau Nama..." 
                className="w-full h-9 pl-9 pr-4 bg-white border border-emerald-50/60 rounded-lg text-xs font-bold text-emerald-950 placeholder:text-black/20 focus:border-[#f3f4f6]0 outline-none transition-all"
              />
            </div>

            <div className="flex flex-wrap items-center gap-2 w-full md:w-auto">
              <select value={periodId} onChange={(e) => { setPeriodId(e.target.value); router.get(route('admin.grade-reports.index'), { period_id: e.target.value }, { preserveState: true }); }} className="h-9 px-3 bg-white border border-emerald-50/60 rounded-lg text-xs font-black text-emerald-950 uppercase tracking-wider outline-none">
                <option value="">Pilih Periode</option>
                {periods.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
              <select value={facultyId} onChange={(e) => setFacultyId(e.target.value)} disabled={!!lockedFaculty} className="h-9 px-3 bg-white border border-emerald-50/60 rounded-lg text-xs font-black text-emerald-950 uppercase tracking-wider outline-none max-w-[150px]">
                <option value="">Fakultas</option>
                {faculties.map(f => <option key={f.id} value={f.id}>{f.name}</option>)}
              </select>
              <select value={huruf} onChange={(e) => setHuruf(e.target.value)} className="h-9 px-3 bg-white border border-emerald-50/60 rounded-lg text-xs font-black text-emerald-950 uppercase tracking-wider outline-none">
                <option value="">Nilai Huruf</option>
                {['A','B','C','D','E'].map(h => <option key={h} value={h}>{h}</option>)}
              </select>
              <Button onClick={() => applyFilters()} className="h-9 px-4 bg-[#e8f5ee] border border-emerald-50 text-[#1a7a4a] hover:bg-[#e8f5ee] text-xs font-black uppercase tracking-widest">
                Terapkan
              </Button>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="bg-emerald-50/20 border-b border-emerald-50/50">
                  <th className="px-8 py-4 text-xs font-black text-emerald-950 uppercase tracking-widest">Identitas Mahasiswa</th>
                  <th className="px-8 py-4 text-xs font-black text-emerald-950 uppercase tracking-widest">Lokasi & Prodi</th>
                  <th className="px-8 py-4 text-xs font-black text-emerald-950 uppercase tracking-widest text-center">Skor Akhir</th>
                  <th className="px-8 py-4 text-xs font-black text-emerald-950 uppercase tracking-widest text-center">Status Berkas</th>
                  <th className="px-8 py-4 text-xs font-black text-emerald-950 uppercase tracking-widest text-right">Tindakan</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[#f3f4f6]/60 font-sans">
                {scores?.map((grade) => (
                  <tr key={grade.id} className="hover:bg-gray-50/20 transition-all group">
                    <td className="px-8 py-5">
                      <div className="flex flex-col">
                        <span className="text-sm font-bold text-emerald-950 uppercase leading-none mb-1.5">{grade.name}</span>
                        <span className="text-xs text-emerald-950/40 font-black tabular-nums tracking-wider uppercase leading-none">NIM: {grade.nim}</span>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-xs font-bold text-emerald-950/80">
                      <div className="flex flex-col">
                        <span className="uppercase leading-none mb-1.5">{grade.group_name}</span>
                        <span className="text-xs text-emerald-950/40 font-black uppercase tracking-tight">{grade.prodi}</span>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <div className="flex flex-col items-center">
                        <span className="text-base font-bold text-emerald-950 tabular-nums leading-none mb-1.5">{Number(grade.final_grade_value || 0).toFixed(2)}</span>
                        <span className="text-[9px] font-black text-white bg-[#16a34a] px-2 py-0.5 rounded shadow-sm">{grade.final_grade_letter || '-'}</span>
                      </div>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <span className={clsx(
                        "inline-flex px-3 py-1 rounded-lg text-[9px] font-black uppercase border transition-all",
                        grade.is_locked ? "bg-[#e8f5ee] text-[#1a7a4a] border-emerald-200" : "bg-white text-emerald-950/10 border-[#f3f4f6]"
                      )}>{grade.is_locked ? 'DIKUNCI' : 'DRAF'}</span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      <div className="flex justify-end opacity-0 group-hover:opacity-100 transition-opacity gap-2">
                        {grade.is_locked && (
                          <>
                            <button 
                              onClick={() => handlePreview(grade.score_id!)}
                              className="h-9 w-9 bg-white text-emerald-600 hover:bg-emerald-50 border border-emerald-100 flex items-center justify-center rounded-xl shadow-sm transition-all"
                              title="Pratinjau Sertifikat"
                            >
                              <FileText size={16} />
                            </button>
                            <button 
                              onClick={() => handleDownloadWord(grade.score_id!)}
                              className="h-9 w-9 bg-white text-[#1a7a4a] hover:bg-emerald-50 border border-emerald-100 flex items-center justify-center rounded-xl shadow-sm transition-all"
                              title="Unduh format Word (.docx)"
                            >
                              <Download size={16} />
                            </button>
                            <a 
                              href={route('admin.grade-reports.sertifikat', grade.score_id!)}
                              className="h-9 w-9 bg-emerald-600 text-white hover:bg-emerald-800 flex items-center justify-center rounded-xl shadow-sm transition-all"
                              title="Unduh format PDF"
                            >
                              <ShieldCheck size={16} />
                            </a>
                          </>
                        )}
                        {grade.can_finalize && !grade.is_locked && (
