import React, { useState } from 'react';
import { Head, Link, router } from '@inertiajs/react';
import AppLayout from '@/Layouts/AppLayout';
import {
  Users, LayoutGrid, FileText, ClipboardList, AlertTriangle, 
  MapPin, Clock, ArrowRight, ShieldCheck, CheckCircle2, ChevronRight, Loader2
} from 'lucide-react';
import { clsx } from 'clsx';
import type { PageProps } from '@/types';
import { motion, AnimatePresence } from 'framer-motion';

// ── Config ───────────────────────────────────────────
interface DashboardProps extends PageProps {
  active_periode_id?: number | null;
  active_period_name?: string | null;
  active_periods?: any[];
  stats?: Record<string, any>;
  current_phase?: Record<string, any> | string;
  recentRegistrations?: any[];
}

const PHASES = [
  { id: 'registration', label: 'Pendaftaran' },
  { id: 'placement',    label: 'Penempatan' },
  { id: 'execution',    label: 'Pelaksanaan' },
  { id: 'grading',      label: 'Penilaian' },
];

const PHASE_LABELS: Record<string, string> = {
  registration: 'Pendaftaran', placement: 'Penempatan',
  execution: 'Pelaksanaan', grading: 'Penilaian',
  upcoming: 'Belum Dimulai', finished: 'Selesai',
};

// ── Main ─────────────────────────────────────────────
export default function Dashboard({
  active_periode_id, active_periods = [],
  stats = {}, current_phase = {}, recentRegistrations = [],
}: DashboardProps) {
  const [switching, setSwitching] = useState(false);
  const [confirmPhase, setConfirmPhase] = useState<string | null>(null);

  const phaseKey = typeof current_phase === 'string'
    ? current_phase : (current_phase?.key || 'upcoming');

  function handlePeriodChange(e: React.ChangeEvent<HTMLSelectElement>) {
    const val = e.target.value;
    if (val) router.get(route('admin.dashboard', { period_id: val }));
  }

  function handlePhaseChange(e: React.ChangeEvent<HTMLSelectElement>) {
    const val = e.target.value;
    if (val && val !== phaseKey && active_periode_id) {
      setConfirmPhase(val);
      // Reset select back to current phase until confirmed
      e.target.value = phaseKey; 
    }
  }

  function submitPhaseChange() {
    if (!active_periode_id || !confirmPhase || switching) return;
    setSwitching(true);
    router.post('/admin/dashboard/switch-phase',
      { target: confirmPhase, periode_id: active_periode_id },
      { preserveScroll: true, onFinish: () => { setSwitching(false); setConfirmPhase(null); } }
    );
  }

  const pendingCount = stats?.pending_registrations ?? 0;
  const unassignedCount = stats?.unassigned_students ?? 0;

  return (
    <AppLayout title="Dashboard">
      <Head title="Dashboard Admin" />

      {/* ── Background Kontras (Slate-50) ── */}
      <div className="min-h-screen bg-slate-50 -m-6 lg:-m-8 p-4 sm:p-6 lg:p-8">
        <div className="max-w-7xl mx-auto space-y-4">

          {/* ── HEADER PANEL (Minimalist & Padat) ── */}
          <div className="bg-white rounded-lg ring-1 ring-slate-200 shadow-sm p-4 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
            <div>
              <h1 className="text-lg font-bold text-slate-900 leading-tight">Dashboard Admin</h1>
              <p className="text-sm text-slate-500">Ringkasan operasional dan status pendaftaran saat ini.</p>
            </div>

            <div className="flex flex-col sm:flex-row items-center gap-3 w-full sm:w-auto">
              {/* Form Select Periode */}
              <div className="w-full sm:w-48">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wide mb-1">
                  Periode KKN
                </label>
                <select
                  value={active_periode_id || ''}
                  onChange={handlePeriodChange}
                  className="w-full bg-white border border-slate-300 text-slate-900 text-sm font-semibold rounded-md focus:ring-emerald-500 focus:border-emerald-500 py-1.5 px-3 shadow-sm"
                >
                  <option value="" disabled>Pilih Periode...</option>
                  {active_periods.map((p: any) => (
                    <option key={p.id} value={p.id}>{p.nama}</option>
                  ))}
                </select>
              </div>

              {/* Form Select Fase */}
              <div className="w-full sm:w-48">
                <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-wide mb-1">
                  Fase Saat Ini
                </label>
                <select
                  value={phaseKey}
                  onChange={handlePhaseChange}
                  className={clsx(
                    "w-full text-sm font-bold rounded-md border focus:ring-2 focus:outline-none py-1.5 px-3 shadow-sm",
                    "bg-emerald-50 border-emerald-300 text-emerald-800 focus:ring-emerald-500 focus:border-emerald-500"
                  )}
                >
                  <option value="upcoming" disabled>Belum Dimulai</option>
                  {PHASES.map((p) => (
                    <option key={p.id} value={p.id}>{p.label}</option>
                  ))}
                  <option value="finished" disabled>Selesai</option>
                </select>
              </div>
            </div>
          </div>

          {/* ── METRICS ROW (Kecil, Kompak, Terbaca Jelas) ── */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <MetricCard title="Total Pendaftar" value={stats?.total_students ?? 0} icon={Users} />
            <MetricCard 
              title="Menunggu Review" 
              value={pendingCount} 
              icon={Clock} 
              alert={pendingCount > 0} 
              color="amber" 
              href={route('admin.pendaftaran.index')} 
            />
            <MetricCard 
              title="Belum Ditempatkan" 
              value={unassignedCount} 
              icon={AlertTriangle} 
              alert={unassignedCount > 0} 
              color="rose" 
            />
            <MetricCard title="Total Kelompok" value={stats?.total_groups ?? 0} icon={LayoutGrid} />
          </div>

          {/* ── MAIN CONTENT (List Padat & Ringkas) ── */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">

            {/* KOLOM KIRI: Pendaftaran Terbaru (Lebar 2/3) */}
            <div className="lg:col-span-2 bg-white rounded-lg ring-1 ring-slate-200 shadow-sm overflow-hidden flex flex-col">
              <div className="bg-slate-50/80 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
                <h2 className="text-sm font-bold text-slate-900 flex items-center gap-2">
                  <ClipboardList size={16} className="text-slate-500" /> Antrian Pendaftaran
                </h2>
                <Link href={route('admin.pendaftaran.index')} className="text-xs font-bold text-emerald-600 hover:text-emerald-800 transition-colors">
                  Lihat Semua &rarr;
                </Link>
              </div>

              <div className="flex-1">
                {recentRegistrations.length > 0 ? (
                  <div className="divide-y divide-slate-100">
                    {recentRegistrations.slice(0, 6).map((reg: any) => (
                      <div key={reg.id} className="flex items-center justify-between px-4 py-2.5 hover:bg-slate-50 transition-colors">
                        <div className="flex items-center gap-3 overflow-hidden">
                          <div className="h-8 w-8 rounded bg-slate-100 border border-slate-200 text-slate-600 flex items-center justify-center text-xs font-bold shrink-0">
                            {reg.mahasiswa?.user?.name?.[0]?.toUpperCase() || '?'}
                          </div>
                          <div className="truncate">
                            <p className="text-sm font-bold text-slate-900 truncate">{reg.mahasiswa?.user?.name || '—'}</p>
                            <p className="text-xs font-medium text-slate-500 truncate">{reg.mahasiswa?.nim || '—'}</p>
                          </div>
                        </div>
                        <span className="shrink-0 ml-4 inline-flex items-center px-2 py-0.5 rounded text-[10px] font-bold bg-amber-100 text-amber-800 border border-amber-200">
                          Review
                        </span>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="p-8 flex flex-col items-center justify-center text-center">
                    <ShieldCheck size={32} className="text-slate-300 mb-2" />
                    <p className="text-sm font-bold text-slate-700">Antrian Kosong</p>
                    <p className="text-xs text-slate-500">Semua pendaftaran telah divalidasi.</p>
                  </div>
                )}
              </div>
            </div>

            {/* KOLOM KANAN: Progres & Pintasan (Lebar 1/3) */}
            <div className="space-y-4">

              {/* Progres Penempatan */}
              <div className="bg-white rounded-lg ring-1 ring-slate-200 shadow-sm p-4">
                <h2 className="text-sm font-bold text-slate-900 mb-3 flex items-center gap-2">
                  <MapPin size={16} className="text-slate-500" /> Progres Penempatan
                </h2>
                <div className="space-y-3">
                  <CompactProgress label="Verifikasi Posko" current={stats?.reported_posko ?? 0} total={stats?.total_groups ?? 1} />
                  <CompactProgress label="Alokasi Mahasiswa" current={stats?.assigned_students ?? 0} total={stats?.total_students ?? 1} />
                </div>
              </div>

              {/* Pesan Peringatan (Jika ada yang belum ditempatkan) */}
              {unassignedCount > 0 && (
                <div className="bg-rose-50 rounded-lg ring-1 ring-rose-200 p-3 flex gap-3">
                  <AlertTriangle size={16} className="text-rose-600 shrink-0 mt-0.5" />
                  <div>
                    <p className="text-xs font-bold text-rose-900 mb-0.5">Tindakan Diperlukan</p>
                    <p className="text-[11px] text-rose-700 leading-tight">
                      <strong className="font-bold">{unassignedCount} mahasiswa</strong> belum dialokasikan ke kelompok KKN.
                    </p>
                  </div>
                </div>
              )}

              {/* Menu Pintasan */}
              <div className="bg-white rounded-lg ring-1 ring-slate-200 shadow-sm overflow-hidden">
                <div className="bg-slate-50/80 px-4 py-2 border-b border-slate-200">
                  <h2 className="text-xs font-bold text-slate-500 uppercase tracking-wider">Akses Cepat</h2>
                </div>
                <div className="divide-y divide-slate-100">
                  <QuickMenu href={route('admin.lokasi.index')} icon={MapPin} label="Kelola Wilayah & Lokasi" />
                  <QuickMenu href={route('admin.mahasiswa.index')} icon={Users} label="Direktori Mahasiswa" />
                  <QuickMenu href={route('admin.kelompok.index')} icon={LayoutGrid} label="Manajemen Kelompok" />
                  <QuickMenu href={route('admin.laporan.harian.index')} icon={FileText} label="Laporan Harian" />
                </div>
              </div>

            </div>
          </div>
        </div>
      </div>

      {/* ── Modal Konfirmasi Ubah Fase ── */}
      <AnimatePresence>
        {confirmPhase && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm">
            <motion.div
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="bg-white rounded-lg shadow-xl w-full max-w-sm overflow-hidden"
            >
              <div className="p-5 border-b border-slate-100">
                <h3 className="text-lg font-bold text-slate-900 flex items-center gap-2">
                  <AlertTriangle className="text-amber-500" size={20} />
                  Konfirmasi Fase
                </h3>
              </div>
              <div className="p-5 bg-slate-50">
                <p className="text-sm text-slate-700 mb-3">
                  Anda akan mengubah status sistem ke fase <strong className="font-bold text-slate-900">"{PHASE_LABELS[confirmPhase]}"</strong>.
                </p>
                <p className="text-xs text-rose-600 font-medium">
                  Perhatian: Tindakan ini akan seketika mengubah menu dan hak akses bagi mahasiswa serta DPL di seluruh portal.
                </p>
              </div>
              <div className="p-4 bg-white flex justify-end gap-2 border-t border-slate-100">
                <button
                  onClick={() => setConfirmPhase(null)}
                  className="px-4 py-2 text-sm font-bold text-slate-700 bg-white border border-slate-300 rounded hover:bg-slate-50"
                >
                  Batal
                </button>
                <button
                  onClick={submitPhaseChange}
                  disabled={switching}
                  className="px-4 py-2 text-sm font-bold text-white bg-emerald-600 rounded hover:bg-emerald-700 flex items-center gap-2 disabled:opacity-50"
                >
                  {switching && <Loader2 size={14} className="animate-spin" />}
                  Ya, Ubah Sekarang
                </button>
              </div>
            </motion.div>
          </div>
        )}
      </AnimatePresence>
    </AppLayout>
  );
}

Dashboard.layout = AppLayout.layout;

// ── Sub-components (Kompak & Bersih) ───────────────────────────────────

function MetricCard({ title, value, icon: Icon, alert = false, color = 'emerald', href }: any) {
  const Wrapper = href ? Link : 'div';
  return (
    <Wrapper 
      {...(href ? { href } : {})}
      className={clsx(
        "bg-white rounded-lg ring-1 shadow-sm p-4 flex items-start justify-between transition-colors",
        alert && color === 'amber' ? "ring-amber-200 bg-amber-50/30" : 
        alert && color === 'rose' ? "ring-rose-200 bg-rose-50/30" : "ring-slate-200",
        href && "hover:bg-slate-50 cursor-pointer"
      )}
    >
      <div>
        <p className="text-xs font-bold text-slate-500 mb-1 uppercase tracking-wide">{title}</p>
        <p className={clsx(
          "text-2xl font-black tabular-nums tracking-tight",
          alert && color === 'amber' ? "text-amber-700" :
          alert && color === 'rose' ? "text-rose-700" : "text-slate-900"
        )}>{value}</p>
      </div>
      <div className={clsx(
        "p-2 rounded-md",
        alert && color === 'amber' ? "bg-amber-100 text-amber-600" :
        alert && color === 'rose' ? "bg-rose-100 text-rose-600" : "bg-slate-100 text-slate-500"
      )}>
        <Icon size={20} strokeWidth={2.5} />
      </div>
    </Wrapper>
  );
}

function CompactProgress({ label, current, total }: { label: string; current: number; total: number }) {
  const safe = total > 0 ? total : 1;
  const pct = Math.min(100, Math.round((current / safe) * 100));

  return (
    <div>
      <div className="flex justify-between items-center mb-1">
        <span className="text-xs font-bold text-slate-700">{label}</span>
        <span className="text-[10px] font-bold text-slate-500 tabular-nums bg-slate-100 px-1.5 py-0.5 rounded border border-slate-200">
          {current}/{total} ({pct}%)
        </span>
      </div>
      <div className="h-1.5 bg-slate-100 rounded-full border border-slate-200 overflow-hidden">
        <div className="h-full bg-emerald-500" style={{ width: `${pct}%` }} />
      </div>
    </div>
  );
}

function QuickMenu({ href, icon: Icon, label }: any) {
  return (
    <Link href={href} className="flex items-center justify-between px-4 py-2.5 hover:bg-slate-50 group transition-colors">
      <div className="flex items-center gap-3 text-slate-700 group-hover:text-emerald-700 transition-colors">
        <Icon size={16} strokeWidth={2.5} className="text-slate-400 group-hover:text-emerald-600" />
        <span className="text-sm font-bold">{label}</span>
      </div>
      <ChevronRight size={16} className="text-slate-300 group-hover:text-emerald-500" />
    </Link>
  );
}

