// Premium Components
import PageHeader from '@/Components/Premium/PageHeader';
import ContentPanel from '@/Components/Premium/ContentPanel';
import StatusTag from '@/Components/Premium/StatusTag';
import SearchInput from '@/Components/Premium/SearchInput';

interface AcademicYear {
  id: number;
  year: string;
  is_active: boolean;
  created_at?: string;
}

interface PaginationPayload<T> {
  data: T[];
  meta?: PaginationMeta;
  current_page?: number;
  last_page?: number;
  per_page?: number;
  total?: number;
  from?: number | null;
  to?: number | null;
  links?: PaginationMeta['links'];
  path?: string;
}

interface Props {
  academicYears: PaginationPayload<AcademicYear>;
  filters: { search?: string };
}

function resolvePaginationMeta(payload: PaginationPayload<unknown>): PaginationMeta | null {
  if (payload.meta) return payload.meta;
  if (payload.last_page && payload.links) {
    return {
      current_page: payload.current_page ?? 1,
      last_page: payload.last_page as number,
      per_page: payload.per_page ?? 15,
      total: payload.total ?? 0,
      from: payload.from ?? null,
      to: payload.to ?? null,
      links: payload.links as any,
      path: payload.path ?? '',
    };
  }
  return null;
}

export default function AcademicYearsIndex({ academicYears, filters }: Props) {
  const [search, setSearch] = useState(filters.search ?? '');
  const [sortConfig, setSortConfig] = useState<{ key: keyof AcademicYear; direction: 'asc' | 'desc' }>({
    key: 'year',
    direction: 'desc'
  });
  const [expandedId, setExpandedId] = useState<number | null>(null);

  const currentYear = new Date().getFullYear();
  const yearOptions = Array.from({ length: 6 }, (_, i) => {
    const startYear = currentYear - 1 + i;
    return `${startYear}/${startYear + 1}`;
  });

  const form = useForm({
    year: '',
    is_active: false,
  });

  useEffect(() => {
    const timer = window.setTimeout(() => {
      if (search !== (filters.search ?? '')) {
        router.get(
          '/admin/tahun-akademik',
          { search: search || undefined },
          { preserveState: true, replace: true, preserveScroll: true },
        );
      }
    }, 400);
    return () => window.clearTimeout(timer);
  }, [filters.search, search]);

  const paginationMeta = resolvePaginationMeta(academicYears);

  const processedRows = useMemo(() => {
    let items = [...(academicYears.data ?? [])];
    return items.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return sortConfig.direction === 'asc' ? aVal.localeCompare(bVal) : bVal.localeCompare(aVal);
      }
      return 0;
    });
  }, [academicYears.data, sortConfig]);

  const toggleSort = (key: keyof AcademicYear) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'desc' ? 'asc' : 'desc'
    }));
  };

  const submit = (event: React.FormEvent) => {
    event.preventDefault();
    form.post('/admin/tahun-akademik', {
      preserveScroll: true,
      onSuccess: () => form.reset(),
    });
  };

  const toggleStatus = (year: AcademicYear) => {
    router.patch(
      `/admin/tahun-akademik/${year.id}`,
      { year: year.year, is_active: !year.is_active },
      { preserveScroll: true },
    );
  };

  const destroy = (year: AcademicYear) => {
    if (confirm(`Data "${year.year}" akan dihapus secara permanen. Lanjutkan?`)) {
      router.delete(`/admin/tahun-akademik/${year.id}`, {
        preserveScroll: true,
      });
    }
  };

  return (
    <AppLayout title="Data Tahun Akademik">
      <Head title="Data Tahun Akademik | SIBERDAYA" />

      <div className="max-w-[1440px] mx-auto px-4 sm:px-6 lg:px-8 py-10 space-y-12 font-sans text-emerald-950">
        <PageHeader 
          title="Tahun Ajaran."
          subtitle="Daftar tahun akademik aktif yang digunakan untuk mengelompokkan periode pelaksanaan KKN."
          icon={LibraryBig}
          groupLabel="Data Master Sistem"
          stats={{
            label: 'Total Terdaftar',
            value: `${(paginationMeta?.total ?? processedRows.length).toLocaleString()} Data`,
            icon: Database
          }}
        />

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 items-start">
          <div className="lg:col-span-1 space-y-6">
            <ContentPanel
              title="Tambah Tahun"
              description="Daftarkan formasi tahun ajaran baru."
              icon={Plus}
              padding={true}
            >
              <form onSubmit={submit} className="space-y-8">
                <div className="space-y-2">
                  <label htmlFor="academic-year" className="text-[10px] font-black text-emerald-950 uppercase tracking-[0.2em] pl-1">
                    Tahun Akademik
                  </label>
                  <select
                    id="academic-year"
                    value={form.data.year}
                    onChange={(event) => form.setData('year', event.target.value)}
                    className="w-full px-5 py-3.5 rounded-2xl border-2 border-slate-50 text-sm font-black text-emerald-950 focus:border-emerald-600 outline-none transition-all bg-[#F8FAF9]"
                  >
                    <option value="" disabled>Pilih Tahun Akademik</option>
                    {yearOptions.map((yearOption) => (
                      <option key={yearOption} value={yearOption}>
                        {yearOption}
                      </option>
                    ))}
                  </select>
                  {form.errors.year && (
                    <p className="text-[10px] font-black text-rose-600 mt-1 uppercase tracking-widest pl-1">{form.errors.year}</p>
                  )}
                </div>

                <div className="flex items-start gap-4 p-5 bg-white rounded-3xl border-2 border-slate-50 shadow-sm">
                  <div className="flex items-center h-5 pt-0.5">
                    <input
                      id="is_active"
