                  </div>
                </div>

                <button
                  type="submit"
                  disabled={form.processing}
                  className="w-full h-14 bg-emerald-600 text-white text-xs font-black rounded-2xl hover:bg-emerald-700 transition-all flex items-center justify-center gap-4 shadow-xl shadow-emerald-200 active:scale-[0.98] uppercase tracking-[0.2em] disabled:opacity-50"
                >
                  {form.processing ? (
                    <RefreshCw size={18} className="animate-spin" />
