                  </div>
                </PremiumTableCell>
                <PremiumTableCell>
                   <span className="px-2.5 py-1 rounded-lg text-[10px] font-black bg-emerald-950 text-emerald-400 border border-emerald-800 uppercase tracking-widest shadow-inner">
                      {period.current_phase.replace('_', ' ')}
                   </span>
                </PremiumTableCell>
