function formatDate(value: string | null) {
 if (!value) return '-';
 return new Date(value).toLocaleDateString('id-ID', { day: '2-digit', month: 'short', year: 'numeric' }).toUpperCase();
}

import AppLayout from '@/Layouts/AppLayout';
import { Head, Link } from '@inertiajs/react';
import {
 Calendar,
 Users,
 MapPin,
 FileText,
 Clock,
 CheckCircle2,
 ChevronLeft,
 BarChart3,
 ArrowRight,
 Target,
 Info,
} from 'lucide-react';
import { clsx } from 'clsx';

interface Props {
 period: {
 id: number;
 name: string;
 academic_year: { name: string };
 registration_start: string;
 registration_end: string;
 execution_start: string;
 execution_end: string;
 grading_start: string;
 grading_end: string;
 status_kkn: string;
 description: string | null;
 is_active: boolean;
 stats?: {
 total_students: number;
 total_groups: number;
 total_locations: number;
 };
 };
}

function formatDate(dateString: string) {
 if (!dateString) return '-';
 return new Intl.DateTimeFormat('id-ID', { dateStyle: 'long' }).format(new Date(dateString));
}

const phaseLabel: Record<string, string> = {
 upcoming: 'Pra-Pendaftaran',
 registration: 'Pendaftaran',
 pendaftaran: 'Pendaftaran',
 placement: 'Plotting Penempatan',
 execution: 'Pelaksanaan Lapangan',
 pelaksanaan: 'Pelaksanaan Lapangan',
 grading: 'Penilaian',
 penilaian: 'Penilaian',
 finished: 'Selesai',
};

export default function PeriodShow({ period }: Props) {
 const currentPhaseLabel = phaseLabel[period.status_kkn] ?? period.status_kkn;

 const timeline = [
 {
 title: 'Pendaftaran Peserta',
 start: period.registration_start,
 end: period.registration_end,
 phase: 'pendaftaran',
 },
