          <div className="space-y-4">
            <div className="h-10 w-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center border border-emerald-100 shadow-sm">
              <ShieldAlert size={20} strokeWidth={2.5} />
            </div>
            <div className="space-y-1">
              <h1 className="text-3xl font-black text-emerald-950 tracking-tight uppercase">
                Otoritas Khusus.
              </h1>
              <p className="text-xs font-bold text-emerald-800 uppercase tracking-widest">
                Pusat kendali otoritas jalur khusus dan monitoring perizinan mahasiswa KKN.
              </p>
            </div>
          </div>

          <div className="bg-white border border-emerald-100 rounded-2xl p-5 flex items-center gap-5 shadow-sm">
             <div className="h-12 w-12 rounded-xl bg-emerald-50 flex items-center justify-center text-emerald-600 border border-emerald-100">
                <Files size={24} />
             </div>
             <div>
                <p className="text-[10px] font-black text-emerald-800 uppercase tracking-widest leading-none mb-1">Total Otoritas</p>
                <h4 className="text-2xl font-black text-emerald-950 tabular-nums leading-none">{dispensasi?.meta?.total} Kasus</h4>
             </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">

          {/* --- LEFT COLUMN: FORMULIR (Standard Pattern) --- */}
          <div className="lg:col-span-4 space-y-6">
            <div className="bg-white border border-emerald-50 rounded-xl overflow-hidden shadow-sm">
              <div className="p-6 border-b border-[#f3f4f6] bg-gray-50 flex items-center gap-4">
                <div className="h-10 w-10 bg-white rounded-lg flex items-center justify-center text-[#1a7a4a] border border-emerald-50">
                  <Plus size={20} strokeWidth={3} />
                </div>
                <div>
                  <h3 className="text-sm font-bold text-emerald-950 uppercase tracking-wider">Formulir Dispensasi</h3>
                  <p className="text-xs font-bold text-emerald-800">INPUT OTORISASI BYPASS SISTEM</p>
                </div>
              </div>

              <form onSubmit={handleSubmit} className="p-8 space-y-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-emerald-950 uppercase tracking-widest pl-1">Mahasiswa [NIM] <span className="text-rose-500">*</span></label>
                  <input 
                    value={form.data.nim} 
                    onChange={e => form.setData('nim', e.target.value)} 
                    className="w-full h-12 px-5 bg-gray-50 border border-emerald-50 rounded-xl text-sm font-bold text-emerald-950 focus:bg-white focus:border-[#f3f4f6]0 outline-none transition-all placeholder:text-black"
                    placeholder="Masukkan NIM..."
                    required 
                  />
                  {form.errors.nim && <p className="text-xs font-bold text-rose-500">{form.errors.nim}</p>}
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-emerald-950 uppercase tracking-widest pl-1">Periode Program</label>
                  <select 
                    value={form.data.period_id} 
                    onChange={e => form.setData('period_id', e.target.value)} 
                    className="w-full h-12 px-5 bg-gray-50 border border-emerald-50 rounded-xl text-sm font-bold text-emerald-950 focus:bg-white focus:border-[#f3f4f6]0 outline-none transition-all"
                  >
                    <option value="">Berlaku Global</option>
                    {periods.map(p => <option key={p.id} value={p.id}>{p.name.toUpperCase()}</option>)}
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-xs font-bold text-emerald-950 uppercase tracking-widest pl-1">Justifikasi <span className="text-rose-500">*</span></label>
                  <textarea 
                    value={form.data.alasan} 
                    onChange={e => form.setData('alasan', e.target.value)} 
                    className="w-full h-24 px-5 py-4 bg-gray-50 border border-emerald-50 rounded-xl text-sm font-bold text-emerald-950 focus:bg-white focus:border-[#f3f4f6]0 outline-none transition-all resize-none"
                    placeholder="Alasan formal dispensasi..."
                    required 
                  />
                </div>

                <div className="space-y-3 pt-2">
                  <label className="text-xs font-bold text-emerald-950 uppercase tracking-widest pl-1">Parameter Bypass</label>
                  <div className="grid grid-cols-1 gap-2">
                    {REQUIREMENT_OPTIONS.map(opt => {
                      const isChecked = form.data.bypassed_requirements.includes(opt.value);
                      return (
                        <button 
                          key={opt.value} 
                          type="button"
                          onClick={() => toggleRequirement(opt.value)} 
                          className={clsx(
                            "flex items-center gap-3 px-4 py-3 rounded-lg border text-left transition-all",
                            isChecked ? "bg-[#16a34a] border-emerald-600 text-white" : "bg-white border-emerald-50 text-emerald-950 hover:bg-gray-50"
                          )}
                        >
                          <div className={clsx("h-4 w-4 rounded border flex items-center justify-center", isChecked ? "bg-white border-white text-[#1a7a4a]" : "bg-gray-50 border-emerald-200")}>
                            {isChecked && <Plus size={12} strokeWidth={4} />}
                          </div>
                          <span className="text-xs font-bold tracking-tight">{opt.label}</span>
                        </button>
                      );
                    })}
                  </div>
                </div>

                <button 
                  type="submit"
                  disabled={form.processing}
                  className="w-full h-14 bg-[#16a34a] hover:bg-[#15803d] text-white rounded-xl shadow-lg shadow-none font-bold text-xs flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50 mt-4"
                >
                  {form.processing ? <RefreshCw size={18} className="animate-spin"/> : <Plus size={18} strokeWidth={3} />}
                  SIMPAN DATA DISPENSASI
                </button>
              </form>
            </div>

