                      "px-6 py-2 rounded-lg text-xs font-bold transition-all flex items-center gap-2",
                      activeTab === 'izin' ? "bg-[#16a34a] text-white shadow-md":"text-emerald-950 hover:bg-gray-50"
                    )}
