        {/* --- FOOTER INFO --- */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-8">
           <div className="flex gap-4 p-6 bg-white border-2 border-[#f3f4f6] rounded-xl shadow-sm">
