          >
            <PremiumTable
              headers={['Desa/Kelurahan', 'Wilayah Administratif', 'Kode BPS', 'Okupansi & Kapasitas', 'Opsi']}
              isEmpty={locations.data.length === 0}
              emptyText="Data lokasi administratif tidak ditemukan."
            >
              {locations.data.map((l) => (
                <PremiumTableRow key={l.id} className={clsx("group", editingLocation?.id === l.id && "bg-emerald-50/50")}>
