                           <span className={clsx(l.groups_count >= (l.capacity || 0) && (l.capacity || 0) > 0 ? 'text-amber-600 font-black' : 'text-emerald-950')}>
                            {l.groups_count}
                          </span>
                        </div>
                        <span className="text-emerald-800/30">/ {l.capacity ?? 0}</span>
                      </div>
                      <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden border border-gray-50 shadow-inner">
                        <div 
                          className={clsx("h-full transition-all rounded-full", ((l.capacity ?? 0) > 0 && l.groups_count >= (l.capacity as number)) ? 'bg-gradient-to-r from-amber-500 to-rose-500' : 'bg-gradient-to-r from-emerald-500 to-emerald-400')} 
                          style={{ width: `${Math.min(100, (l.groups_count / (l.capacity || 1)) * 100)}%` }} 
                        />
