import { Head, Link, useForm } from '@inertiajs/react';
import { useMemo, useState } from 'react';
import AppLayout from '@/Layouts/AppLayout';
import {
  User,
  FileText,
  ShieldCheck,
  ArrowLeft,
  Clock,
  Users,
  Search,
  Activity,
  Target,
  Briefcase,
  Database,
  CheckCircle2,
  AlertCircle,
  GraduationCap,
  History,
  Phone,
  MapPin,
  AtSign,
  BookOpen,
  CalendarDays,
  CheckCircle,
  XCircle,
  Fingerprint,
  RefreshCw
} from 'lucide-react';
import { clsx } from 'clsx';
import { motion, AnimatePresence } from 'framer-motion';

// Premium Components
import PageHeader from '@/Components/Premium/PageHeader';
import ContentPanel from '@/Components/Premium/ContentPanel';
import StatCard from '@/Components/Premium/StatCard';
import StatusTag from '@/Components/Premium/StatusTag';

interface RegistrationDocument {
  id: number;
  document_type?: string | null;
  file_name?: string | null;
  file_path?: string | null;
  status?: string | null;
}

interface RegistrationData {
  id: number;
  status: string;
  registration_date?: string | null;
  notes?: string | null;
  rejection_reason?: string | null;
  revision_count?: number | null;
  last_rejected_at?: string | null;
  resubmitted_at?: string | null;
  role?: string | null;
  mahasiswa?: {
    nim?: string | null;
    nik?: string | null;
    nama?: string | null;
    gender?: string | null;
    batch_year?: number | null;
    gpa?: number | null;
    sks_completed?: number | null;
    is_bta_ppi_passed?: boolean | null;
    birth_place?: string | null;
    birth_date?: string | null;
    fakultas?: { nama?: string | null } | null;
    prodi?: { nama?: string | null } | null;
    user?: {
      avatar?: string | null;
      email?: string | null;
      phone?: string | null;
      address?: string | null;
    } | null;
  } | null;
  periode?: {
    name?: string | null;
    governance?: {
      program_type_label?: string | null;
      program_subtype_label?: string | null;
      registration_mode_label?: string | null;
      placement_mode_label?: string | null;
    } | null;
  } | null;
  kelompok?: { nama_kelompok?: string | null; code?: string | null } | null;
  dokumen?: RegistrationDocument[];
}

interface Props {
  registration: RegistrationData;
}

export default function RegistrationShow({ registration }: Props) {
  const [showRejectForm, setShowRejectForm] = useState(false);
  const approveForm = useForm({});
  const rejectForm = useForm({
    notes: registration.rejection_reason ?? '',
  });

  const documents = useMemo(() => registration.dokumen ?? [], [registration.dokumen]);
  const isPending = ['menunggu', 'pending', 'document_submitted'].includes(registration.status);

  const formatDate = (dateString?: string | null) => {
    if (!dateString) return '-';
    return new Date(dateString).toLocaleDateString('id-ID', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
    });
  };

  const getAvatarUrl = () => {
    if (registration.mahasiswa?.user?.avatar) {
      return `/storage/${registration.mahasiswa.user.avatar}`;
    }
    return null;
  };

  return (
    <AppLayout title="Detail Pendaftaran">
      <Head title={`Pendaftaran: ${registration.mahasiswa?.nama || '-'}`} />

      <div className="space-y-6 font-sans pb-12 text-emerald-950">

        {/* BREADCRUMB HEADER */}
        <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 pb-4 border-b border-emerald-50 pt-6">
          <div className="space-y-1">
            <div className="flex items-center gap-2">
              <ShieldCheck size={16} className="text-[#1a7a4a]"/>
              <span className="text-xs font-bold text-emerald-800 uppercase tracking-widest">Audit & Otorisasi</span>
            </div>
            <h1 className="text-2xl font-black text-emerald-950 leading-tight">Detail Pendaftaran.</h1>
          </div>

          <div className="flex items-center gap-4 shrink-0">
             <StatusTag status={registration.status} />
             <Link
                href="/admin/pendaftaran"
                className="h-9 px-4 bg-white border border-gray-200 text-emerald-900 text-xs font-black uppercase tracking-widest rounded-lg transition-all active:scale-95 no-underline flex items-center gap-2 shadow-sm hover:border-emerald-600"
              >
                <ArrowLeft size={14} strokeWidth={2.5} /> Kembali
              </Link>
          </div>
        </div>

        {/* COMPACT STAT ROW */}
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <CompactStat label="ID Pendaftaran" value={`#REG-${registration.id}`} icon={Fingerprint} />
          <CompactStat label="Audit Berkas" value={`${documents.length} File`} icon={Database} />
          <CompactStat label="Unit / Kelompok" value={registration.kelompok?.code || 'MENUNGGU'} icon={Users} />
          <CompactStat label="Periode" value={registration.periode?.name || '-'} icon={CalendarDays} />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">

          <div className="lg:col-span-2 space-y-6">
            {/* DATA MAHASISWA WITH COMPACT PHOTO */}
            <ContentPanel title="Data Identitas Mahasiswa" icon={User}>
              <div className="flex flex-col md:flex-row gap-8 items-start py-2">
                {/* PHOTO - COMPACT SQUARE */}
                <div className="shrink-0">
                  <div className="h-32 w-32 rounded-xl bg-gray-50 border border-emerald-50 overflow-hidden shadow-sm relative group">
                    {getAvatarUrl() ? (
                      <img src={getAvatarUrl() ?? undefined} alt="Avatar" className="h-full w-full object-cover transition-transform group-hover:scale-110" />
                    ) : (
                      <div className="h-full w-full flex items-center justify-center text-gray-200">
                        <User size={48} strokeWidth={1} />
                      </div>
                    )}
                  </div>
                </div>

                {/* INFO GRID */}
                <div className="flex-1 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-y-6 gap-x-8 w-full">
                  <SimpleItem label="Nama Lengkap" value={registration.mahasiswa?.nama} />
                  <SimpleItem label="NIM" value={registration.mahasiswa?.nim} />
                  <SimpleItem label="NIK" value={registration.mahasiswa?.nik} />
                  <SimpleItem label="Fakultas" value={registration.mahasiswa?.fakultas?.nama} />
                  <SimpleItem label="Program Studi" value={registration.mahasiswa?.prodi?.nama} />
                  <SimpleItem label="Angkatan" value={registration.mahasiswa?.batch_year?.toString()} />
                  <SimpleItem label="Gender" value={registration.mahasiswa?.gender === 'L' ? 'LAKI-LAKI' : 'PEREMPUAN'} />
                  <SimpleItem label="Telepon/WA" value={registration.mahasiswa?.user?.phone} />
                  <SimpleItem label="Email" value={registration.mahasiswa?.user?.email} />
                  <div className="md:col-span-2 lg:col-span-3">
                     <SimpleItem label="Alamat Domisili" value={registration.mahasiswa?.user?.address} />
                  </div>
                </div>
              </div>
            </ContentPanel>

            {/* DOKUMEN VAULT - COMPACT LIST */}
            <ContentPanel title="Berkas Persyaratan" icon={FileText} padding={false}>
              <div className="divide-y divide-gray-50 border-t border-gray-50">
                {documents.length > 0 ? (
                  documents.map((doc) => (
                    <div key={doc.id} className="px-6 py-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                      <div className="flex items-center gap-3 overflow-hidden">
                        <div className="h-8 w-8 bg-[#e8f5ee] text-[#1a7a4a] rounded-lg flex items-center justify-center shrink-0">
                          <FileText size={16} />
                        </div>
                        <div className="flex flex-col overflow-hidden">
                          <span className="text-xs font-black text-emerald-950 uppercase tracking-tight truncate">{doc.document_type}</span>
                          <span className="text-xs text-emerald-800 font-mono truncate">{doc.file_name}</span>
                        </div>
                      </div>
                      <div className="flex items-center gap-4 shrink-0 ml-4">
                        <StatusTag status={doc.status || 'pending'} />
                        <a 
                          href={`/admin/pendaftaran/berkas/unduh?path=${doc.file_path}`} target="_blank" rel="noopener noreferrer"
                          className="h-8 px-3 bg-white border border-emerald-50 text-emerald-600 text-xs font-black uppercase rounded-lg hover:bg-emerald-950 hover:text-white transition-all no-underline flex items-center gap-2 shadow-sm"
                        >
                          Lihat <ExternalLink size={12} />
                        </a>
                      </div>
                    </div>
                  ))
                ) : (
                  <div className="p-12 text-center text-xs font-bold text-emerald-800 uppercase tracking-widest">Belum ada berkas pendukung.</div>
                )}
              </div>
            </ContentPanel>
          </div>

          <div className="space-y-6">
            {/* COMPACT ACADEMIC PREREQUISITES */}
            <ContentPanel title="Audit Prasyarat" icon={GraduationCap}>
              <div className="space-y-3">
                <StatusItem label="Kredit SKS (>100)" value={`${registration.mahasiswa?.sks_completed ?? 0} SKS`} isValid={(registration.mahasiswa?.sks_completed ?? 0) >= 100} />
                <StatusItem label="Indeks Prestasi" value={registration.mahasiswa?.gpa?.toFixed(2) || '0.00'} isValid={(registration.mahasiswa?.gpa ?? 0) >= 2.0} />
                <StatusItem label="Status BTA/PPI" value={registration.mahasiswa?.is_bta_ppi_passed ? "LULUS" : "TIDAK LULUS"} isValid={!!registration.mahasiswa?.is_bta_ppi_passed} />
              </div>
            </ContentPanel>

            {/* ACTION HUB */}
            <ContentPanel title="Otorisasi Status" icon={ShieldCheck}>
               <div className="space-y-4">
                 <AnimatePresence mode="wait">
                    {isPending ? (
                      !showRejectForm ? (
                        <div className="grid gap-3">
                           {Object.keys(approveForm.errors).length > 0 && (
                             <div className="p-3 bg-rose-50 text-rose-700 text-xs rounded-xl font-medium border border-rose-100">
                               {Object.values(approveForm.errors).map((err, i) => <div key={i}>{err}</div>)}
                             </div>
                           )}
                           <button
                            onClick={() => approveForm.patch(`/admin/pendaftaran/${registration.id}/setujui`)}
                            disabled={approveForm.processing}
                            className="w-full h-11 bg-emerald-600 hover:bg-emerald-700 text-white text-xs font-black uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-none disabled:opacity-50 flex items-center justify-center gap-3"
                          >
                             {approveForm.processing ? <RefreshCw className="animate-spin h-4 w-4" /> : <CheckCircle2 className="h-4 w-4" strokeWidth={3} />}
                             Sahkan Pendaftaran
                          </button>
                          <button
                            onClick={() => setShowRejectForm(true)}
                            className="w-full h-10 border border-emerald-50 text-rose-600 text-xs font-black uppercase tracking-widest rounded-xl hover:bg-rose-50 transition-colors"
                          >
                            Tolak / Revisi
                          </button>
                        </div>
                      ) : (
                        <motion.form
                          initial={{ opacity: 0, y: 5 }}
                          animate={{ opacity: 1, y: 0 }}
                          onSubmit={(e) => {
                            e.preventDefault();
                            rejectForm.patch(`/admin/pendaftaran/${registration.id}/tolak`, { onSuccess: () => setShowRejectForm(false) });
                          }}
                          className="space-y-3"
                        >
                          {Object.keys(rejectForm.errors).length > 0 && (
                            <div className="p-3 bg-rose-50 text-rose-700 text-xs rounded-xl font-medium border border-rose-100">
                              {Object.values(rejectForm.errors).map((err, i) => <div key={i}>{err}</div>)}
                            </div>
                          )}
                          <textarea
                            required placeholder="Tulis alasan penolakan..."
                            value={rejectForm.data.notes}
                            onChange={(e) => rejectForm.setData('notes', e.target.value)}
                            className="w-full h-24 p-3 bg-gray-50 border border-emerald-50 rounded-xl text-xs font-bold text-emerald-950 focus:ring-[#1a7a4a] focus:border-[#f3f4f6]0 outline-none transition-all placeholder:text-black"
                          />
                          <div className="flex gap-2">
                            <button type="button" onClick={() => setShowRejectForm(false)} className="flex-1 h-9 bg-gray-100 text-emerald-800 text-[9px] font-black uppercase rounded-lg">Batal</button>
                            <button type="submit" disabled={rejectForm.processing} className="flex-[2] h-9 bg-rose-600 text-white text-[9px] font-black uppercase tracking-widest rounded-lg">Kirim Penolakan</button>
                          </div>
                        </motion.form>
                      )
                    ) : (
                       <div className="p-4 bg-gray-50 border border-emerald-50 rounded-xl space-y-3">
                         <div className="flex items-center justify-between">
                            <span className="text-[9px] font-black text-emerald-950/40 uppercase tracking-widest">Keputusan Akhir</span>
                            <StatusTag status={registration.status} />
                         </div>
                         <p className="text-xs font-bold text-emerald-950 italic leading-relaxed">
                           "{registration.status === 'rejected' ? registration.rejection_reason : (registration.notes || 'REGISTRASI DINYATAKAN VALID.')}"
                         </p>
                       </div>
                    )}
                  </AnimatePresence>
               </div>
            </ContentPanel>
          </div>

        </div>
      </div>
    </AppLayout>
  );
}

function CompactStat({ label, value, icon: Icon }: { label: string; value: any; icon: any }) {
  return (
    <div className="bg-white border border-emerald-50 p-4 rounded-xl shadow-sm flex items-center gap-4 hover:border-emerald-50 transition-colors group">
       <div className="h-10 w-10 bg-[#e8f5ee] text-[#1a7a4a] rounded-lg flex items-center justify-center shrink-0 shadow-inner group-hover:scale-110 transition-transform">
         <Icon size={18} strokeWidth={3} />
       </div>
       <div className="flex flex-col overflow-hidden">
         <span className="text-[9px] font-black text-emerald-800 uppercase tracking-widest mb-0.5">{label}</span>
         <span className="text-xs font-black text-emerald-950 truncate"title={value}>{value}</span>
       </div>
    </div>
  );
}

function SimpleItem({ label, value }: { label: string; value?: string | null }) {
  return (
    <div className="flex flex-col gap-1">
      <span className="text-[9px] font-black text-emerald-800 uppercase tracking-widest mb-0.5">{label}</span>
      <span className="text-xs font-black text-emerald-950 uppercase leading-snug">{value || '-'}</span>
    </div>
  );
}

function StatusItem({ label, value, isValid }: { label: string; value: string; isValid: boolean }) {
  return (
    <div className="flex items-center justify-between p-3 bg-white border border-gray-100 rounded-xl">
      <span className="text-xs font-black text-emerald-800 uppercase tracking-tight">{label}</span>
      <div className="flex items-center gap-2">
        <span className={clsx("text-xs font-black", isValid ? "text-[#1a7a4a]" : "text-rose-600")}>{value}</span>
        {isValid ? <CheckCircle size={14} className="text-[#1a7a4a]" strokeWidth={3} /> : <AlertCircle size={14} className="text-rose-400" strokeWidth={3} />}
      </div>
    </div>
  );
}

function ExternalLink({ size }: { size: number }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2 2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg>
  );
}

import { useState } from 'react';
import { router, Head } from '@inertiajs/react';
import AppLayout from '@/Layouts/AppLayout';
import {
  Search, ArrowRightLeft, MapPin, AlertTriangle, UserCircle, Zap, Filter
} from 'lucide-react';
import { clsx } from 'clsx';
import { Pagination, Button } from '@/Components/ui';
import type { PaginationMeta } from '@/Components/ui/Pagination';

interface Student {
  id: number;
  mahasiswa: {
    nim: string;
    nama: string;
    user: { name: string };
  };
  kelompok?: {
    id: number;
    nama_kelompok: string;
    code: string;
    lokasi?: { district_name: string; village_name: string | null; regency_name: string };
  };
  status: string;
}

interface TargetGroup {
  id: number;
  nama: string;
  capacity: number | null;
  current_count: number;
  available: number | null;
}

interface Props {
  students: { data: Student[]; meta: PaginationMeta };
  targetPeriods: Array<{ id: number; name: string; periode: number; jenis: string; kuota: number }>;
  filters: { search?: string };
}

export default function StudentTransfer({ students, targetPeriods, filters }: Props) {
  const [search, setSearch] = useState(filters.search || '');
  const [selectedStudent, setSelectedStudent] = useState<Student | null>(null);
  const [targetGroupId, setTargetGroupId] = useState<string>('');
  const [targetPeriodId, setTargetPeriodId] = useState<string>('');
  const [reason, setReason] = useState('');
  const [groups, setGroups] = useState<TargetGroup[]>([]);
  const [isLoadingGroups, setIsLoadingGroups] = useState(false);

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    router.get('/admin/peserta/pindah', { search }, { preserveState: true });
  };

  const fetchGroups = async (periodId: string) => {
    if (!periodId) { setGroups([]); return; }
    setIsLoadingGroups(true);
    try {
      const response = await fetch(`/admin/api/transfer-targets?target_period_id=${periodId}`);
      const data = await response.json();
      setGroups(data.groups || []);
    } catch (_e) { /* ignore network errors */ } finally { setIsLoadingGroups(false); }
  };

  const handleTransfer = () => {
    if (!selectedStudent || !targetPeriodId || !reason.trim()) return;
    if (confirm(`Mutasi Peserta: ${selectedStudent.mahasiswa.nama}? Pastikan data tujuan sudah benar.`)) {
      router.post('/admin/peserta/pindah', { 
        peserta_kkn_id: selectedStudent.id, 
        target_period_id: targetPeriodId, 
        target_group_id: targetGroupId || null, 
        reason 
      }, {
        onSuccess: () => { 
          setSelectedStudent(null); 
          setTargetGroupId(''); 
          setTargetPeriodId(''); 
          setReason(''); 
        },
      });
    }
  };

  return (
    <AppLayout title="Transfer Peserta">
      <Head title="Manajemen Mutasi Peserta | SIBERDAYA" />

      <div className="max-w-[1600px] mx-auto space-y-8 pb-24 font-sans px-4 sm:px-6 lg:px-8">

        {/* HEADER SECTION IN CLEAN EMERALD */}
        <div className="bg-white border-2 border-gray-100 rounded-[2rem] p-8 relative overflow-hidden flex flex-col md:flex-row items-start justify-between gap-8 group">
          <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-emerald-50/30 rounded-full blur-3xl -translate-y-1/2 translate-x-1/3 pointer-events-none transition-transform group-hover:scale-110 duration-1000" />

          <div className="relative z-10 flex gap-6 items-start">
            <div className="h-20 w-20 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-xl shadow-emerald-600/20 shrink-0">
              <ArrowRightLeft size={36} strokeWidth={2.5} />
            </div>
            <div className="space-y-2">
              <span className="text-xs font-black text-emerald-700 uppercase tracking-widest bg-emerald-50 px-3 py-1 rounded-full border border-emerald-100/50 w-fit">
                Operasi Basis Data
              </span>
              <h1 className="text-3xl font-black text-emerald-950 tracking-tight leading-none uppercase">
                Mutasi Peserta 
              </h1>
              <p className="text-sm font-bold text-emerald-800 max-w-xl leading-relaxed">
                Protokol administrasi instan untuk menggeser penempatan personil KKN lintas kelompok atau siklus periode secara aman dan akurat.
              </p>
            </div>
          </div>

          <div className="relative z-10 hidden md:flex items-center gap-6 bg-emerald-50 px-8 py-6 rounded-[2rem] shrink-0 border border-emerald-100">
            <div className="flex flex-col text-right">
              <span className="text-xs font-black text-emerald-700 uppercase tracking-widest mb-1">Total Peserta Valid</span>
              <span className="text-4xl font-black text-emerald-950 leading-none tabular-nums">{students.meta.total.toLocaleString('id-ID')}</span>
            </div>
            <div className="h-12 w-12 bg-white rounded-xl flex items-center justify-center text-emerald-600 border border-emerald-100 shadow-sm shrink-0">
              <Zap size={24} strokeWidth={3} />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 items-start">
          {/* --- LEFT COLUMN: SEARCH & SELECTION (1/3 LAYOUT) --- */}
          <div className="lg:col-span-4 flex flex-col bg-white border border-emerald-100 rounded-xl overflow-hidden h-[800px] shadow-sm">
            <div className="p-6 border-b border-gray-100 bg-white">
              <form onSubmit={handleSearch} className="relative group">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-emerald-600 group-focus-within:text-emerald-700 transition-colors" />
                <input 
                  type="text"
                  value={search} 
                  onChange={(e) => setSearch(e.target.value)} 
                  className="w-full h-14 pl-12 pr-6 bg-gray-50 border border-gray-200 rounded-xl text-xs font-bold text-emerald-950 uppercase tracking-wider focus:border-emerald-500 focus:bg-white transition-all outline-none"
                  placeholder="CARI NIM / NAMA MAHASISWA..."
                />
              </form>
            </div>

            <div className="flex-1 overflow-y-auto divide-y divide-gray-100 custom-scrollbar p-6">
              {students.data.map(s => (
                <button 
                  key={s.id} 
                  onClick={() => setSelectedStudent(s)} 
                  className={clsx(
                    'w-full p-5 text-left transition-all duration-300 flex flex-col gap-2 rounded-xl mb-3', 
                    selectedStudent?.id === s.id 
                    ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-900/20 translate-x-2' 
                    : 'bg-white hover:bg-emerald-50/50 border border-emerald-50 text-emerald-950 hover:translate-x-1'
                  )}
                >
                  <span className={clsx('text-xs font-black uppercase tracking-widest', selectedStudent?.id === s.id ? 'text-emerald-200' : 'text-emerald-600')}>
