import { Head, useForm, router } from '@inertiajs/react';
import { useState, useMemo } from 'react';
import AppLayout from '@/Layouts/AppLayout';
import { Button, FormSelect } from '@/Components/ui';
import {
  Star,
  Users,
  Save,
  FileSpreadsheet,
  CheckCircle2,
  AlertCircle,
  MoreVertical,
  Lock,
  Search,
  MapPin,
  GraduationCap,
  ArrowRight,
} from 'lucide-react';
