                                {cat.key === 'report' && student.ai_performance?.has_data && (
                                  <button
                                    type="button"
                                    onClick={() =>
                                      handleScoreChange(
                                        student.id,
                                        cat.criterion,
                                        String(student.ai_performance?.suggested_admin_score || 0),
