      router.reload({ only: ['user'] });
    }).catch(() => {
      setPreviewUrl(null);
    });
  };

  const avatarUrl = previewUrl || (user.avatar ? `/storage/${user.avatar}` : null);

  // Biodata status
  const isStudent = !!student;
  const isLecturer = !!lecturer;

