                      <span className="text-sm font-mono font-bold text-gray-900">{sertifikat.certificate_number}</span>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 pt-4 border-t border-gray-50">
                    <div>
