                  </div>

                  {isRevoked && (
                    <div className="mt-6 p-4 bg-rose-50 border border-rose-100 rounded-xl flex items-start gap-3">
                      <XCircle size={20} className="text-rose-600 shrink-0 mt-0.5" />
                      <div>
