                 >
                   Detail Posko
                 </Link>
              </div>
            </motion.div>
          )}

          {/* --- MAIN GRID --- */}
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">

            {/* Left Content (8 Cols) */}
            <div className="lg:col-span-8 space-y-6">

              {/* Progress Tracker Card */}
              <div className="bg-white rounded-[2.5rem] p-8 shadow-sm border border-emerald-50">
